	for _, e := range result.Record.Evidence {
		if e.Kind == domain.EvidenceKindLint && strings.Contains(e.Source, ":unit") {
			if !e.Passed {
				t.Error("per-unit lint for foo.go should pass (findings are in bar.go)")
